import{c as t,Q as a,j as r,m as p}from"./chunks/framework.hhGiamYR.js";const d=JSON.parse('{"title":"2026-05-31","description":"","frontmatter":{"date":"2026-05-31T00:00:00.000Z","source":"machiavelli/florentine/book3.md","chapter":"第三卷·第一章","tags":["派系","自由","权力","人性","佛罗伦萨史"]},"headers":[],"relativePath":"fragments/2026-05-31.md","filePath":"fragments/2026-05-31.md"}'),o={name:"fragments/2026-05-31.md"};function n(s,e,_,c,i,l){return a(),r("div",null,[...e[0]||(e[0]=[p('<h1 id="_2026-05-31" tabindex="-1">2026-05-31 <a class="header-anchor" href="#_2026-05-31" aria-label="Permalink to &quot;2026-05-31&quot;">​</a></h1><blockquote><p><em>来源：《佛罗伦萨史》第三卷·第一章</em></p></blockquote><hr><p>罗马人争的是一席之地，佛罗伦萨人争的是对方的消失。——前者叫政治，后者叫仇恨。两件事长得太像了，人们总是搞混。</p><hr><p>他写：贵族的骄横和野心并未死亡，只不过从他们身上转移到某些平民身上而已。</p><p>这句话让我停下来。不是因为陌生，而是因为太熟悉了。所谓革命，有时只是换了一批人继续享用同一套权术。</p><hr><p>「那些领袖人物满口仁义道德，用花言巧语把卑鄙龌龊的阴谋诡计神圣化。」</p><p>他不是在骂某一个人。他是在描述一种结构：语言总是先于行动腐烂。</p><hr><p>里奇家族本想用旧法律打击阿尔比齐，结果那条法律反而让阿尔比齐声望大涨。——用来绊倒别人的石头，有时会变成别人的阶梯。</p><p>他好像很喜欢记录这类讽刺。不是因为残忍，而是因为诚实。</p><hr><p>「看来几乎是命里注定似的，在所有共和国中，都有所谓&#39;致命的家族&#39;，天生下来就是为了毁灭自己的国家。」</p><p>他用了「命里注定」这个词，但他不信命。他是在说：这不是命运，这是结构；只是人们太习惯把结构的重复叫做命运。</p>',16)])])}const h=t(o,[["render",n]]);export{d as __pageData,h as default};
